// 1. Definisikan aturan kata kunci & skor
const KEYWORDS_RIGHT_ISSUE = ["right issue", "hm etd", "hmetd", "pmhmetd", "pm hm etd", "pmhm etd"];

const KEYWORDS_UTAMA = {
    "Akuisisi": ["akuisisi", "mengakuisisi"],
    "Pengambilalihan": ["pengambilalihan", "takeover"],
    "Perubahan Pengendali": ["perubahan pengendali", "pengendali baru", "perubahan kepemilikan"],
    "Inbreng / Setoran Aset": ["inbreng", "setoran aset", "penyertaan aset", "penambahan modal non kas"],
    "Transaksi Material": ["transaksi material"],
    "Afiliasi": ["afiliasi"],
    "Right Issue": ["right issue", "rights issue", "hmetd", "penerbitan saham baru"], 
    "Penambahan Modal": ["penambahan modal", "private placement"] // "ihsg" SUDAH DILEPAS DARI SINI
};

// Keyword khusus untuk fallback (Prioritas Terakhir)
const KEYWORDS_IHSG = ["ihsg", "indeks harga saham gabungan"];

const SCORE_MAP = {
    "Akuisisi": 3,
    "Pengambilalihan": 3,
    "Perubahan Pengendali": 3,
    "Inbreng / Setoran Aset": 3,
    "Right Issue": 2,
    "Penambahan Modal": 2,
    "Transaksi Material": 2,
    "Afiliasi": 1
};

// 2. Ambil data masuk dari seluruh RSS
const items = $input.all();
let processedNews = [];
let seenLinks = new Set();

for (let item of items) {
    const title = (item.json.title || '').toLowerCase();
    const link = item.json.link || '';

    if (!title || !link || seenLinks.has(link)) continue;

    let score = 0;
    let matched = false;

    // Prioritas 1: Cek Right Issue terlebih dahulu agar tidak double count
    let isRightIssue = KEYWORDS_RIGHT_ISSUE.some(kw => title.includes(kw));
    if (isRightIssue) {
        score += SCORE_MAP["Right Issue"];
        matched = true;
    }

    // Prioritas 2: Cek kategori utama lainnya
    for (let [category, kws] of Object.entries(KEYWORDS_UTAMA)) {
        if (category === "Right Issue" && isRightIssue) continue;

        if (kws.some(kw => title.includes(kw))) {
            score += SCORE_MAP[category] || 0;
            matched = true;
        }
    }

    // Prioritas 3: JIKA KEYWORD UTAMA TIDAK ADA, BARU BAHAS IHSG
    if (!matched) {
        let isIHSG = KEYWORDS_IHSG.some(kw => title.includes(kw));
        if (isIHSG) {
            score = 0.5; // Skor terkecil agar selalu berada di posisi paling bawah/akhir
            matched = true;
        }
    }

    if (matched && score > 0) {
        seenLinks.add(link);
        processedNews.push({
            judul: item.json.title.trim(),
            link: link.trim(),
            score: score
        });
    }
}

// 3. Sorting berdasarkan Score tertinggi
processedNews.sort((a, b) => b.score - a.score);

// 4. Potong langsung menjadi maksimal 10 berita teratas (Tanpa dipisah)
const topNews = processedNews.slice(0, 10);

// Jika tidak ada berita sama sekali, hentikan workflow
if (topNews.length === 0) {
    return []; 
}

const output = [];

// 5. Format Menjadi Satu Pesan Tunggal
let telegramMessage = "⚡ *TOP 10 BERITA SAHAM PILIHAN* ⚡\n\n";
topNews.forEach((news, index) => {
    telegramMessage += `${index + 1}. [${news.judul}] : ${news.link}\n\n`;
});

output.push({ json: { sendMessage: true, text: telegramMessage } });

return output;
